public function testRoundTrip_XdrAccountID_corpus_account_id_g(): void
{
    $base64 = 'AAAAAGL8HQvQkbK2HA3WVjRrKmjX00fG8sLI7m0ERwJW/AX3';
    $instance = \Soneso\StellarSDK\Xdr\XdrAccountID::fromBase64Xdr($base64);
    $jsonValue = $instance->toJsonValue();
    $json = $instance->toJson();
    // toJsonValue stability across two independent decodes of the
    // same XDR base64 — catches non-determinism in the toJsonValue
    // path.
    $instance2 = \Soneso\StellarSDK\Xdr\XdrAccountID::fromBase64Xdr($base64);
    $this->assertSame($jsonValue, $instance2->toJsonValue(),
        'corpus[account_id_g] toJsonValue not deterministic across decodes');
    $decoded = \Soneso\StellarSDK\Xdr\XdrAccountID::fromJsonValue($jsonValue);
    $this->assertSame(
        $jsonValue,
        $decoded->toJsonValue(),
        'corpus[account_id_g] toJsonValue idempotence broken'
    );
    $reparsed = \Soneso\StellarSDK\Xdr\XdrAccountID::fromJson($json);
    $this->assertSame($json, $reparsed->toJson(),
        'corpus[account_id_g] toJson idempotence broken');
    $reEncodedXdr = $decoded->toBase64Xdr();
    $reInstance = \Soneso\StellarSDK\Xdr\XdrAccountID::fromBase64Xdr($reEncodedXdr);
    $this->assertSame($jsonValue, $reInstance->toJsonValue(),
        'corpus[account_id_g] XDR-JSON-XDR round trip diverged');
}

